sql:
SELECT city, COUNT(service_id) AS number_of_services
FROM ambulance_services
GROUP BY city;

external_knowledge:
- "running for over three years" refers to the condition where the current year minus the year of enumeration_date is greater than 3;
- "firms" refers to the companies providing ambulance services;
- "zones" refers to the geographic areas covered by the services;
- "taken on some cases" refers to having at least one request associated with them;
- "can handle at least ten patients" refers to the service_capacity being greater than or equal to 10;
- "still active" means the service status is 'Active'.

sql:
SELECT service_id, company_name, service_capacity
FROM ambulance_services
WHERE service_capacity > (SELECT AVG(service_capacity) FROM ambulance_services);

SELECT status_name
FROM statuses
WHERE status_code = 'NW';

SELECT COUNT(service_id) AS service_count, AVG(service_capacity) AS average_capacity
FROM ambulance_services
WHERE state = 'PA' AND service_capacity > 3;

SELECT COUNT(*)
FROM ambulance_services
WHERE city = 'New York City' AND status = 'Active';

external_knowledge:
- Significant number of requests refers to a minimum of 100 service requests;
- The past year refers to the year 2022;
- Special instructions are indicated when the 'special_requests' field is not null.

- Small: Fleet size of 100 or fewer vehicles; 
- Highly capable: Service capacity greater than 100 patients;
- Treated: Service request status is 'Completed'.

sql:
SELECT company_name, city
FROM ambulance_services
WHERE city = 'Philadelphia' AND status = 'Active';

external_knowledge:
- "thriving" refers to the status 'Active';
- "minimum of five patients" refers to service_capacity >= 5;
- "since their sails were first raised" refers to since enumeration_date;
- "initial voyage into the sea of service" refers to enumeration_date;
- "navigating the waves of demand" metaphorically refers to serving patients.

- "prime of their operational years" metaphorically refers to ambulance services with an 'Active' status;
- The capacity of the service corresponds to how many patients it can transport at once, metaphorically its "fleet size" and "operational prime";
- "Bustling fleets" refers to the number of vehicles in the service's fleet, with a higher number indicating a more comprehensive service capacity.

sql:
SELECT AVG(service_capacity) AS AvgServiceCapacity
FROM ambulance_services
WHERE status = 'Active' AND city = 'New York';

SELECT ambulance_services.company_name, statuses.status_name
FROM ambulance_services
JOIN statuses ON ambulance_services.status = statuses.status_code;
